changeSet.sql:
UPDATE part SET barcode = NULL WHERE id IN (SELECT id FROM (SELECT id, ROW_NUMBER() OVER (PARTITION BY company_id, barcode ORDER BY id) as row_num FROM part WHERE barcode IS NOT NULL) sub WHERE sub.row_num > 1);
ALTER TABLE part ADD CONSTRAINT uq_part_company_barcode UNIQUE (company_id, barcode);
UPDATE asset SET bar_code = NULL WHERE id IN (SELECT id FROM (SELECT id, ROW_NUMBER() OVER (PARTITION BY company_id, bar_code ORDER BY id) as row_num FROM asset WHERE bar_code IS NOT NULL) sub WHERE sub.row_num > 1);
ALTER TABLE asset ADD CONSTRAINT uq_asset_company_barcode UNIQUE (company_id, bar_code);
